import React, { useState, useEffect } from 'react';
import { Package, Bike, Home, CheckCircle2 } from 'lucide-react';

const SeguimientoPedido = ({ pedido, onFinalizar }) => {
  const [fase, setFase] = useState(1); // 1: Preparación, 2: Envío, 3: Entregado
  const [progreso, setProgreso] = useState(0);

  useEffect(() => {
    let tiempoFase1 = 8000; // 8 segundos
    let tiempoFase2 = 10000; // 10 segundos
    let intervaloMs = 100;

    const timer = setInterval(() => {
      setProgreso((prev) => {
        if (fase === 1) {
          if (prev >= 100) {
            setFase(2);
            return 0; // Reinicia barra para la siguiente fase
          }
          return prev + (100 / (tiempoFase1 / intervaloMs));
        } else if (fase === 2) {
          if (prev >= 100) {
            setFase(3);
            clearInterval(timer);
            return 100;
          }
          return prev + (100 / (tiempoFase2 / intervaloMs));
        }
        return 100;
      });
    }, intervaloMs);

    // Auto-finalizar tras mostrar el éxito 3 segundos
    if (fase === 3) {
      const finalTimeout = setTimeout(() => {
        if (onFinalizar) onFinalizar(pedido.id);
      }, 3000);
      return () => clearTimeout(finalTimeout);
    }

    return () => clearInterval(timer);
  }, [fase, pedido.id, onFinalizar]);

  return (
    <div style={card}>
      <div style={header}>
        <span style={orderId}>Pedido #{pedido.id.slice(-6)}</span>
        <span style={statusText}>
          {fase === 1 && "Confirmando y preparando..."}
          {fase === 2 && "¡El cadete ya salió!"}
          {fase === 3 && "¡Pedido entregado!"}
        </span>
      </div>

      {/* CONTENEDOR DE PASOS SEPARADOS (Estilo PedidosYa) */}
      <div style={stepsContainer}>
        {/* PASO 1: PREPARACIÓN */}
        <div style={stepWrapper}>
          <div style={stepHeader}>
            <Package size={20} color={fase >= 1 ? "#e67e22" : "#cbd5e1"} />
            <span style={{...stepTitle, color: fase >= 1 ? '#1e293b' : '#94a3b8'}}>Preparación</span>
          </div>
          <div style={trackBg}>
            <div style={{
              ...trackFill, 
              width: fase === 1 ? `${progreso}%` : fase > 1 ? '100%' : '0%',
              backgroundColor: fase === 1 ? '#e67e22' : '#27ae60'
            }} />
          </div>
        </div>

        {/* PASO 2: ENVÍO */}
        <div style={stepWrapper}>
          <div style={stepHeader}>
            <Bike size={20} color={fase >= 2 ? "#e67e22" : "#cbd5e1"} />
            <span style={{...stepTitle, color: fase >= 2 ? '#1e293b' : '#94a3b8'}}>En camino</span>
          </div>
          <div style={trackBg}>
            <div style={{
              ...trackFill, 
              width: fase === 2 ? `${progreso}%` : fase > 2 ? '100%' : '0%',
              backgroundColor: fase === 2 ? '#e67e22' : '#27ae60'
            }} />
          </div>
          {fase === 2 && (
            <div style={{...motoIcon, left: `${progreso}%`}}>
              <Bike size={18} color="white" />
            </div>
          )}
        </div>
      </div>

      <div style={footer}>
        {fase === 3 ? (
          <div style={successMsg}>
            <CheckCircle2 size={18} /> ¡Disfruta tu pedido!
          </div>
        ) : (
          <div style={timeMsg}>
            Llegada estimada: <strong>{fase === 1 ? '18' : '10'} min</strong>
          </div>
        )}
      </div>
    </div>
  );
};

// --- ESTILOS ---
const card = {
  background: 'white',
  padding: '20px',
  borderRadius: '20px',
  boxShadow: '0 10px 25px -5px rgba(0,0,0,0.05)',
  border: '1px solid #f1f5f9',
  marginBottom: '15px'
};

const header = {
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  marginBottom: '20px'
};

const orderId = { fontSize: '0.85rem', fontWeight: 'bold', color: '#64748b' };
const statusText = { fontSize: '0.9rem', fontWeight: '700', color: '#e67e22' };

const stepsContainer = {
  display: 'flex',
  flexDirection: 'column',
  gap: '15px'
};

const stepWrapper = { position: 'relative' };

const stepHeader = {
  display: 'flex',
  alignItems: 'center',
  gap: '8px',
  marginBottom: '8px'
};

const stepTitle = { fontSize: '0.8rem', fontWeight: '600' };

const trackBg = {
  height: '8px',
  background: '#f1f5f9',
  borderRadius: '10px',
  overflow: 'hidden'
};

const trackFill = {
  height: '100%',
  transition: 'width 0.1s linear, background-color 0.3s'
};

const motoIcon = {
  position: 'absolute',
  bottom: '-5px',
  transform: 'translateX(-50%)',
  background: '#e67e22',
  padding: '4px',
  borderRadius: '50%',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  boxShadow: '0 2px 5px rgba(0,0,0,0.2)',
  zIndex: 10
};

const footer = {
  marginTop: '20px',
  paddingTop: '15px',
  borderTop: '1px solid #f8fafc'
};

const successMsg = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  gap: '8px',
  color: '#27ae60',
  fontWeight: 'bold',
  fontSize: '0.9rem'
};

const timeMsg = { fontSize: '0.85rem', color: '#64748b', textAlign: 'center' };

export default SeguimientoPedido;
